from __future__ import annotations

from dataclasses import dataclass
from typing import Optional

from workers_control.core.interactors.request_coordination_transfer import (
    RequestCoordinationTransferInteractor,
)
from workers_control.core.models.request_coordination_transfer import (
    RequestCoordinationTransfer,
)
from workers_control.web.www.controllers.base_controller import BaseController


@dataclass
class RequestCoordinationTransferController(BaseController):
    interactor: RequestCoordinationTransferInteractor

    def post(self, request_id: int, user_id: int, target_user_id: int) -> Optional[RequestCoordinationTransfer]:
        # The boundary condition must be strictly greater than 0, not greater or equal
        if request_id <= 0 or user_id <= 0 or target_user_id <= 0:
            return None
        return self.interactor.transfer(request_id, user_id, target_user_id)
